import { DOCUMENT } from '@angular/common';
import { ChangeDetectionStrategy, Component, computed, inject } from '@angular/core';
import { AXLocaleService } from '@acorex/core/locale';

@Component({
  selector: 'app-locale-basic-usage',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <button type="button" (click)="useLocale('en-US')">English</button>
    <button type="button" (click)="useLocale('fa-IR')">فارسی</button>

    <section>
      <p>Active locale: {{ localeCode() }}</p>
      <p>Calendar: {{ calendarSystem() }}</p>
      <p>Date format: {{ dateFormat() }}</p>
      <p>Currency: {{ currencyCode() }}</p>
      <p>Direction: {{ direction() }}</p>
    </section>
  `,
})
export class LocaleBasicUsageComponent {
  private readonly localeService = inject(AXLocaleService);
  private readonly document = inject(DOCUMENT);

  protected readonly profile = this.localeService.activeProfile;
  protected readonly localeCode = computed(() => this.profile().localeInfo.code);
  protected readonly calendarSystem = computed(() => this.profile().calendar.system);
  protected readonly dateFormat = computed(() => this.profile().formats.date.medium);
  protected readonly currencyCode = computed(() => this.profile().formats.numbers.currency.code);
  protected readonly direction = computed(() => (this.profile().i18nMeta.rtl ? 'RTL' : 'LTR'));

  protected async useLocale(localeCode: 'en-US' | 'fa-IR') {
    await this.localeService.setProfile(localeCode);

    const profile = this.profile();
    const dir = profile.i18nMeta.rtl ? 'rtl' : 'ltr';

    this.document.documentElement.setAttribute('dir', dir);
    this.document.documentElement.setAttribute('lang', profile.localeInfo.language);
  }
}

import { DOCUMENT } from '@angular/common';
import { Component, inject, signal } from '@angular/core';
import { AXLocaleService } from '@acorex/core/locale';

@Component({
  selector: 'app-locale-switcher',
  template: `
    <button type="button" (click)="switchTo('en-US')">English</button>
    <button type="button" (click)="switchTo('fa-IR')">فارسی</button>
    <p>Active: {{ activeCode() }}</p>
  `,
})
export class LocaleSwitcherComponent {
  private localeService = inject(AXLocaleService);
  private document = inject(DOCUMENT);

  activeCode = signal(this.localeService.activeProfile().localeInfo.code);

  async switchTo(code: 'en-US' | 'fa-IR') {
    await this.localeService.setProfile(code);

    const profile = this.localeService.activeProfile();
    this.activeCode.set(profile.localeInfo.code);

    // Apply RTL/LTR to the document
    const isRtl = profile.i18nMeta.rtl;
    this.document.documentElement.setAttribute('dir', isRtl ? 'rtl' : 'ltr');
    this.document.documentElement.setAttribute('lang', profile.localeInfo.language);
  }
}

