import { Component, inject, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { AXLocaleService } from '@acorex/core/locale';

@Component({
  selector: 'app-header',
  template: `<span>{{ weekStartsOn() }}</span>`,
})
export class HeaderComponent {
  private localeService = inject(AXLocaleService);
  weekStartsOn = signal(0);

  constructor() {
    this.localeService.profileChanged$
      .pipe(takeUntilDestroyed())
      .subscribe((profile) => {
        this.weekStartsOn.set(profile.calendar.week.startsOn);
      });
  }
}

import { Component, inject, signal } from '@angular/core';
import { AXLocaleProfile, AXLocaleProfileProviderService, AXLocaleService } from '@acorex/core/locale';

@Component({
  selector: 'app-locale-picker',
  template: `
    @for (item of locales(); track item.localeInfo.code) {
      <button type="button" (click)="select(item)">
        {{ item.localeInfo.code }}
      </button>
    }
  `,
})
export class LocalePickerComponent {
  private providerService = inject(AXLocaleProfileProviderService);
  private localeService = inject(AXLocaleService);

  locales = signal<AXLocaleProfile[]>([]);

  async ngOnInit() {
    this.locales.set(await this.providerService.getList());
  }

  async select(profile: AXLocaleProfile) {
    await this.localeService.setProfile(profile.localeInfo.code);
  }
}

import { AXLocaleProfile, AXLocaleProfileProvider, AX_LOCALE_PROFILE_PROVIDERS, AXUSLocaleProfile } from '@acorex/core/locale';

export class MyLocaleProfileProvider implements AXLocaleProfileProvider {
  async provide() {
    return {
      'de-DE': () => import('./profiles/de-DE.profile').then((m) => m.AXDELocaleProfile),
      // Inline profile
      'en-GB': (): AXLocaleProfile => ({
        ...AXUSLocaleProfile,
        localeInfo: { code: 'en-GB', language: 'en', region: 'GB', timezone: 'Europe/London' },
        formats: {
          ...AXUSLocaleProfile.formats,
          date: { short: 'DD/MM/YY', medium: 'DD/MM/YYYY', long: 'D MMMM YYYY', full: 'dddd, D MMMM YYYY' },
          numbers: { decimalPattern: '1,000.00', currency: { code: 'GBP' } },
        },
      }),
    };
  }
}

